 {"id":"bd-2nt4","title":"Unit tests for atomic rate limiter","description":"## Purpose
Comprehensive unit tests for the atomic rate limiter (tryConsume method), ensuring no race conditions under concurrent access.

## Test File Location
`apps/gateway/src/middleware/__tests__/rate-limit.test.ts`

## Test Cases

### 1. Basic Functionality
```typescript
describe("InMemoryRateLimiter.tryConsume - basic operations", () => {
  let limiter: InMemoryRateLimiter;

  beforeEach(() => {
    limiter = new InMemoryRateLimiter();
    console.log("[TEST] Created fresh limiter instance");
  });

  it("should allow first request and consume slot", () => {
    const config = { limit: 10, windowMs: 60000 };
    const result = limiter.tryConsume("test-key", config);

    expect(result.allowed).toBe(true);
    expect(result.info.remaining).toBe(9);
    expect(result.info.limit).toBe(10);
    expect(result.info.exceeded).toBe(false);
    console.log(`[TEST] First request: allowed=${result.allowed}, remaining=${result.info.remaining}`);
  });

  it("should correctly decrement remaining with each request", () => {
    const config = { limit: 5, windowMs: 60000 };

    for (let i = 0; i < 5; i++) {
      const result = limiter.tryConsume("test-key", config);
      expect(result.info.remaining).toBe(4 - i);
      console.log(`[TEST] Request ${i + 1}: remaining=${result.info.remaining}`);
    }
  });

  it("should deny request when limit reached", () => {
    const config = { limit: 3, windowMs: 60000 };

    // Consume all slots
    for (let i = 0; i < 3; i++) {
      limiter.tryConsume("test-key", config);
    }

    // Next request should be denied
    const result = limiter.tryConsume("test-key", config);
    expect(result.allowed).toBe(false);
    expect(result.info.remaining).toBe(0);
    expect(result.info.exceeded).toBe(true);
    console.log("[TEST] PASS: Request denied when limit reached");
  });

  it("should NOT consume slot when denied", () => {
    const config = { limit: 2, windowMs: 60000 };

    // Hit the limit
    limiter.tryConsume("test-key", config);
    limiter.tryConsume("test-key", config);

    // Try 10 more times - count should stay at 2
    for (let i = 0; i < 10; i++) {
      const result = limiter.tryConsume("test-key", config);
      expect(result.allowed).toBe(false);
    }

    // Internal count should still be 2, not 12
    const info = limiter.peek("test-key", config);
    expect(info.remaining).toBe(0);
    console.log("[TEST] PASS: Denied requests do not consume slots");
  });
});
```

### 2. Window Reset Behavior
```typescript
describe("InMemoryRateLimiter.tryConsume - window reset", () => {
  it("should reset counter after window expires", async () => {
    jest.useFakeTimers();
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 1, windowMs: 1000 };

    // Use the one allowed request
    let result = limiter.tryConsume("test-key", config);
    expect(result.allowed).toBe(true);

    // Should be denied now
    result = limiter.tryConsume("test-key", config);
    expect(result.allowed).toBe(false);
    console.log("[TEST] Request denied before window reset");

    // Advance past window
    jest.advanceTimersByTime(1001);

    // Should be allowed again
    result = limiter.tryConsume("test-key", config);
    expect(result.allowed).toBe(true);
    expect(result.info.remaining).toBe(0);  // Used the new slot
    console.log("[TEST] PASS: Window reset allows new requests");

    jest.useRealTimers();
  });

  it("should provide correct reset timestamp", () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 10, windowMs: 60000 };
    const beforeRequest = Math.floor(Date.now() / 1000);

    const result = limiter.tryConsume("test-key", config);

    // Reset should be ~60 seconds from now
    expect(result.info.reset).toBeGreaterThanOrEqual(beforeRequest + 59);
    expect(result.info.reset).toBeLessThanOrEqual(beforeRequest + 61);
    console.log(`[TEST] Reset timestamp: ${result.info.reset} (now+60s)`);
  });
});
```

### 3. Multi-Key Independence
```typescript
describe("InMemoryRateLimiter.tryConsume - key isolation", () => {
  it("should track different keys independently", () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 2, windowMs: 60000 };

    // Exhaust key1
    limiter.tryConsume("key1", config);
    limiter.tryConsume("key1", config);

    // key1 should be denied
    expect(limiter.tryConsume("key1", config).allowed).toBe(false);

    // key2 should still work
    expect(limiter.tryConsume("key2", config).allowed).toBe(true);
    expect(limiter.tryConsume("key2", config).allowed).toBe(true);
    expect(limiter.tryConsume("key2", config).allowed).toBe(false);

    console.log("[TEST] PASS: Keys are isolated");
  });

  it("should handle many concurrent keys", () => {
    const limiter = new InMemoryRateLimiter(60000, 10000);
    const config = { limit: 1, windowMs: 60000 };

    // Create 1000 different keys
    for (let i = 0; i < 1000; i++) {
      const result = limiter.tryConsume(`key-${i}`, config);
      expect(result.allowed).toBe(true);
    }

    expect(limiter.size()).toBe(1000);
    console.log(`[TEST] PASS: Handled 1000 distinct keys`);
  });
});
```

### 4. Concurrency Simulation (CRITICAL)
```typescript
describe("InMemoryRateLimiter.tryConsume - concurrency", () => {
  it("should allow exactly limit requests under concurrent load", async () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 100, windowMs: 60000 };
    const startTime = Date.now();

    // Simulate 1000 concurrent requests
    const promises = Array.from({ length: 1000 }, () =>
      Promise.resolve(limiter.tryConsume("burst-key", config))
    );

    const results = await Promise.all(promises);
    const elapsed = Date.now() - startTime;

    const allowed = results.filter(r => r.allowed).length;
    const denied = results.filter(r => !r.allowed).length;

    console.log(`[TEST] Concurrent test: ${allowed} allowed, ${denied} denied in ${elapsed}ms`);

    // CRITICAL: Exactly 100 should be allowed, not more
    expect(allowed).toBe(100);
    expect(denied).toBe(900);
    console.log("[TEST] PASS: No race condition - exactly limit requests allowed");
  });

  it("should handle interleaved requests across multiple keys", async () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 10, windowMs: 60000 };

    // Interleave requests across 10 keys
    const promises = Array.from({ length: 500 }, (_, i) =>
      Promise.resolve(limiter.tryConsume(`key-${i % 10}`, config))
    );

    const results = await Promise.all(promises);
    const allowedByKey = new Map<string, number>();

    results.forEach((r, i) => {
      const key = `key-${i % 10}`;
      if (r.allowed) {
        allowedByKey.set(key, (allowedByKey.get(key) || 0) + 1);
      }
    });

    // Each key should have exactly 10 allowed
    for (let i = 0; i < 10; i++) {
      expect(allowedByKey.get(`key-${i}`)).toBe(10);
    }
    console.log("[TEST] PASS: Interleaved requests handled correctly");
  });
});
```

### 5. Memory Management
```typescript
describe("InMemoryRateLimiter - memory management", () => {
  it("should enforce maxItems limit", () => {
    const limiter = new InMemoryRateLimiter(60000, 100);  // maxItems=100
    const config = { limit: 10, windowMs: 60000 };

    // Create 200 keys
    for (let i = 0; i < 200; i++) {
      limiter.tryConsume(`key-${i}`, config);
    }

    // Should be limited to 100
    expect(limiter.size()).toBeLessThanOrEqual(100);
    console.log(`[TEST] Size after 200 keys: ${limiter.size()}`);
  });

  it("should cleanup expired entries", async () => {
    jest.useFakeTimers();
    const limiter = new InMemoryRateLimiter(100, 1000);  // cleanup every 100ms
    const config = { limit: 10, windowMs: 500 };  // 500ms window

    // Create entries
    limiter.tryConsume("key1", config);
    limiter.tryConsume("key2", config);
    expect(limiter.size()).toBe(2);

    // Advance past window expiry
    jest.advanceTimersByTime(600);

    // Manual cleanup
    const removed = limiter.cleanup();
    expect(removed).toBe(2);
    expect(limiter.size()).toBe(0);
    console.log(`[TEST] Cleanup removed ${removed} expired entries`);

    jest.useRealTimers();
  });
});
```

### 6. Edge Cases
```typescript
describe("InMemoryRateLimiter.tryConsume - edge cases", () => {
  it("should handle limit of 0 (always deny)", () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 0, windowMs: 60000 };

    const result = limiter.tryConsume("test", config);
    expect(result.allowed).toBe(false);
    console.log("[TEST] PASS: limit=0 always denies");
  });

  it("should handle limit of 1", () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 1, windowMs: 60000 };

    expect(limiter.tryConsume("test", config).allowed).toBe(true);
    expect(limiter.tryConsume("test", config).allowed).toBe(false);
    console.log("[TEST] PASS: limit=1 allows exactly one request");
  });

  it("should handle very large limits", () => {
    const limiter = new InMemoryRateLimiter();
    const config = { limit: 1000000, windowMs: 60000 };

    const result = limiter.tryConsume("test", config);
    expect(result.allowed).toBe(true);
    expect(result.info.remaining).toBe(999999);
    console.log("[TEST] PASS: Large limits handled");
  });
});
```

