 {"id":"bd-2plz","title":"Unit tests for conversation history sliding window","description":"## Purpose
Comprehensive unit tests for the conversation history sliding window implementation, ensuring memory is bounded while preserving critical messages.

## Test File Location
`packages/agent-drivers/src/__tests__/conversation-history.test.ts`

## Test Cases

### 1. Basic Truncation
```typescript
describe("Conversation History - basic truncation", () => {
  let driver: TestableDriver;

  beforeEach(() => {
    driver = createTestDriver({ 
      maxHistoryMessages: 10,
      maxHistoryTokens: 10000,
    });
  });

  it("should truncate history when exceeding maxHistoryMessages", async () => {
    const session = await driver.createSession();

    // Add system message + 15 user messages
    session.conversationHistory = [
      { role: "system", content: "You are helpful", timestamp: new Date() },
    ];

    for (let i = 0; i < 15; i++) {
      session.conversationHistory.push({
        role: "user",
        content: `Message ${i}`,
        timestamp: new Date(),
      });
      console.log(`[TEST] Added message ${i}, history length: ${session.conversationHistory.length}`);
    }

    // Trigger pruning
    driver.pruneConversationHistory(session);

    // Should have system + 9 recent messages = 10 total
    expect(session.conversationHistory.length).toBe(10);
    console.log(`[TEST] After prune: ${session.conversationHistory.length} messages`);

    // First message should still be system
    expect(session.conversationHistory[0].role).toBe("system");
    console.log("[TEST] PASS: System message preserved at index 0");

    // Last message should be "Message 14" (most recent)
    expect(session.conversationHistory[9].content).toBe("Message 14");
    console.log("[TEST] PASS: Most recent messages retained");
  });

  it("should not truncate when at exactly maxHistoryMessages", async () => {
    const session = await driver.createSession();

    session.conversationHistory = [
      { role: "system", content: "System" },
      ...Array.from({ length: 9 }, (_, i) => ({ role: "user", content: `Msg ${i}` })),
    ];

    const originalLength = session.conversationHistory.length;
    driver.pruneConversationHistory(session);

    expect(session.conversationHistory.length).toBe(originalLength);
    console.log("[TEST] PASS: No truncation at exact limit");
  });

  it("should not truncate when under maxHistoryMessages", async () => {
    const session = await driver.createSession();

    session.conversationHistory = [
      { role: "system", content: "System" },
      { role: "user", content: "Hello" },
    ];

    driver.pruneConversationHistory(session);
    expect(session.conversationHistory.length).toBe(2);
    console.log("[TEST] PASS: No truncation under limit");
  });
});
```

### 2. System Message Preservation
```typescript
describe("Conversation History - system message preservation", () => {
  it("should always preserve system message at index 0", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 5 });
    const session = await driver.createSession();

    const systemMessage = { 
      role: "system", 
      content: "CRITICAL: You must always do X", 
      timestamp: new Date(0),  // Old timestamp
    };

    session.conversationHistory = [
      systemMessage,
      ...Array.from({ length: 20 }, () => ({ role: "user", content: "Hi" })),
    ];

    driver.pruneConversationHistory(session);

    expect(session.conversationHistory[0]).toEqual(systemMessage);
    expect(session.conversationHistory[0].content).toBe("CRITICAL: You must always do X");
    console.log("[TEST] PASS: System message with old timestamp still preserved");
  });

  it("should handle history with no system message", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 5 });
    const session = await driver.createSession();

    // No system message - all user/assistant
    session.conversationHistory = Array.from({ length: 10 }, (_, i) => ({
      role: i % 2 === 0 ? "user" : "assistant",
      content: `Message ${i}`,
    }));

    driver.pruneConversationHistory(session);

    expect(session.conversationHistory.length).toBe(5);
    // Most recent 5 should be kept
    expect(session.conversationHistory[0].content).toBe("Message 5");
    console.log("[TEST] PASS: Handles missing system message");
  });

  it("should handle multiple system messages (keep only first)", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 5 });
    const session = await driver.createSession();

    session.conversationHistory = [
      { role: "system", content: "First system" },
      { role: "user", content: "Hello" },
      { role: "system", content: "Second system (injected)" },  // Unusual but possible
      ...Array.from({ length: 10 }, () => ({ role: "user", content: "Hi" })),
    ];

    driver.pruneConversationHistory(session);

    // First system message should be preserved
    expect(session.conversationHistory[0].content).toBe("First system");
    console.log("[TEST] PASS: First system message preserved");
  });
});
```

### 3. Token-Based Truncation
```typescript
describe("Conversation History - token-based truncation", () => {
  const mockTokenCounter = (text: string): number => {
    // Simple approximation: ~4 chars per token
    return Math.ceil(text.length / 4);
  };

  it("should truncate when total tokens exceed maxHistoryTokens", async () => {
    const driver = createTestDriver({ 
      maxHistoryMessages: 100,  // High message limit
      maxHistoryTokens: 100,    // Low token limit
      tokenCounter: mockTokenCounter,
    });

    const session = await driver.createSession();
    session.conversationHistory = [
      { role: "system", content: "Short system" },  // ~4 tokens
      { role: "user", content: "A".repeat(200) },   // ~50 tokens
      { role: "assistant", content: "B".repeat(200) }, // ~50 tokens
      { role: "user", content: "C".repeat(200) },   // ~50 tokens
    ];
    // Total: ~154 tokens, exceeds 100

    const beforeCount = session.conversationHistory.length;
    driver.pruneConversationHistory(session);
    const afterCount = session.conversationHistory.length;

    console.log(`[TEST] Before: ${beforeCount} messages, After: ${afterCount} messages`);

    // Should have removed oldest non-system messages
    expect(afterCount).toBeLessThan(beforeCount);

    // Calculate remaining tokens
    const remainingTokens = session.conversationHistory.reduce(
      (sum, msg) => sum + mockTokenCounter(msg.content as string),
      0
    );
    console.log(`[TEST] Remaining tokens: ${remainingTokens}`);
    expect(remainingTokens).toBeLessThanOrEqual(100);
  });

  it("should prefer keeping recent messages when truncating by tokens", async () => {
    const driver = createTestDriver({ 
      maxHistoryTokens: 50,
      tokenCounter: mockTokenCounter,
    });

    const session = await driver.createSession();
    session.conversationHistory = [
      { role: "system", content: "Sys" },
      { role: "user", content: "OLD_MESSAGE_1" },
      { role: "user", content: "OLD_MESSAGE_2" },
      { role: "user", content: "RECENT_MSG" },
    ];

    driver.pruneConversationHistory(session);

    const contents = session.conversationHistory.map(m => m.content);
    expect(contents).toContain("RECENT_MSG");
    expect(contents).toContain("Sys");
    console.log(`[TEST] Retained: ${contents.join(", ")}`);
  });
});
```

### 4. Multiple Sessions Isolation
```typescript
describe("Conversation History - session isolation", () => {
  it("should truncate each session independently", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 5 });

    const session1 = await driver.createSession();
    const session2 = await driver.createSession();

    // Session 1: 10 messages
    session1.conversationHistory = Array.from({ length: 10 }, (_, i) => ({
      role: "user",
      content: `S1-Msg-${i}`,
    }));

    // Session 2: 3 messages (under limit)
    session2.conversationHistory = Array.from({ length: 3 }, (_, i) => ({
      role: "user",
      content: `S2-Msg-${i}`,
    }));

    driver.pruneConversationHistory(session1);
    driver.pruneConversationHistory(session2);

    expect(session1.conversationHistory.length).toBe(5);
    expect(session2.conversationHistory.length).toBe(3);  // Unchanged
    console.log("[TEST] PASS: Sessions truncated independently");
  });
});
```

### 5. Edge Cases
```typescript
describe("Conversation History - edge cases", () => {
  it("should handle empty history", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 10 });
    const session = await driver.createSession();
    session.conversationHistory = [];

    expect(() => driver.pruneConversationHistory(session)).not.toThrow();
    expect(session.conversationHistory.length).toBe(0);
    console.log("[TEST] PASS: Empty history handled");
  });

  it("should handle history with only system message", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 10 });
    const session = await driver.createSession();
    session.conversationHistory = [{ role: "system", content: "System" }];

    driver.pruneConversationHistory(session);
    expect(session.conversationHistory.length).toBe(1);
    console.log("[TEST] PASS: System-only history handled");
  });

  it("should handle null/undefined content gracefully", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 5 });
    const session = await driver.createSession();
    session.conversationHistory = [
      { role: "system", content: "Sys" },
      { role: "user", content: null as any },
      { role: "assistant", content: undefined as any },
      { role: "user", content: "Valid" },
    ];

    expect(() => driver.pruneConversationHistory(session)).not.toThrow();
    console.log("[TEST] PASS: Null/undefined content handled");
  });

  it("should preserve message metadata during truncation", async () => {
    const driver = createTestDriver({ maxHistoryMessages: 3 });
    const session = await driver.createSession();

    const messageWithMetadata = {
      role: "user",
      content: "Important",
      timestamp: new Date("2024-01-01"),
      metadata: { tool_call_id: "abc123" },
    };

    session.conversationHistory = [
      { role: "system", content: "Sys" },
      { role: "user", content: "Old" },
      messageWithMetadata,
    ];

    driver.pruneConversationHistory(session);

    const preserved = session.conversationHistory.find(
      m => m.content === "Important"
    );
    expect(preserved?.metadata).toEqual({ tool_call_id: "abc123" });
    console.log("[TEST] PASS: Metadata preserved during truncation");
  });
});
```

