### 1. Error Propagation Tests
```typescript
describe("Data hooks - error propagation", () => {
  const originalEnv = process.env.NODE_ENV;

  beforeAll(() => {
    process.env.NODE_ENV = "production";
    console.log("[TEST] Running in production mode");
  });

  afterAll(() => {
    process.env.NODE_ENV = originalEnv;
  });

  describe("useSnapshot", () => {
    it("should set error state when API fails in production", async () => {
      server.use(
        rest.get("/api/snapshot", (req, res, ctx) => {
          console.log("[MSW] Returning 500 error for /api/snapshot");
          return res(ctx.status(500), ctx.json({ error: "Internal error" }));
        })
      );

      const { result, waitFor } = renderHook(() => useSnapshot());

      await waitFor(() => \!result.current.isLoading);

      expect(result.current.error).toBeInstanceOf(Error);
      expect(result.current.error?.message).toContain("500");
      expect(result.current.data).toBeNull();  // NOT mock data\!
      expect(result.current.usingMockData).toBe(false);

      console.log("[TEST] PASS: Error propagated, no mock data in production");
    });

    it("should set error state for network failures", async () => {
      server.use(
        rest.get("/api/snapshot", (req, res) => {
          console.log("[MSW] Simulating network error");
          return res.networkError("Connection refused");
        })
      );

      const { result, waitFor } = renderHook(() => useSnapshot());
      await waitFor(() => \!result.current.isLoading);

      expect(result.current.error).toBeDefined();
      expect(result.current.data).toBeNull();
      console.log("[TEST] PASS: Network error propagated correctly");
    });

    it("should include error details in error object", async () => {
      server.use(
        rest.get("/api/snapshot", (req, res, ctx) => {
          return res(ctx.status(503), ctx.json({ 
            error: "Service unavailable",
            code: "SERVICE_DOWN",
            retryAfter: 30,
          }));
        })
      );

      const { result, waitFor } = renderHook(() => useSnapshot());
      await waitFor(() => \!result.current.isLoading);

      const error = result.current.error;
      expect(error?.message).toContain("503");
      // Error should preserve server details for debugging
      console.log(`[TEST] Error details: ${error?.message}`);
    });
  });

  describe("useDCG", () => {
    it("should NOT fall back to mock commands on API error", async () => {
      server.use(
        rest.get("/api/dcg/commands", (req, res, ctx) => {
          return res(ctx.status(500));
        })
      );

      const { result, waitFor } = renderHook(() => useDCG());
      await waitFor(() => \!result.current.isLoading);

      expect(result.current.commands).toBeNull();
      expect(result.current.error).toBeDefined();
      console.log("[TEST] PASS: useDCG does not use mock data on error");
    });
  });

  describe("useFleet", () => {
    it("should NOT fall back to mock agents on API error", async () => {
      server.use(
        rest.get("/api/agents", (req, res, ctx) => {
          return res(ctx.status(502));
        })
      );

      const { result, waitFor } = renderHook(() => useFleet());
      await waitFor(() => \!result.current.isLoading);

      expect(result.current.agents).toEqual([]);  // Empty, not mock agents
      expect(result.current.error).toBeDefined();
      console.log("[TEST] PASS: useFleet returns empty array, not mock data");
    });
  });
});
