### 4. Retry Mechanism Tests
```typescript
describe("Data hooks - retry functionality", () => {
  it("should provide refetch function that clears error on success", async () => {
    let callCount = 0;
    server.use(
      rest.get("/api/snapshot", (req, res, ctx) => {
        callCount++;
        if (callCount === 1) {
          return res(ctx.status(500));
        }
        return res(ctx.json({ agents: [], timestamp: Date.now() }));
      })
    );

    const { result, waitFor } = renderHook(() => useSnapshot());

    // First call fails
    await waitFor(() => result.current.error \!== null);
    expect(result.current.error).toBeDefined();
    console.log("[TEST] First fetch failed as expected");

    // Retry
    act(() => {
      result.current.refetch();
    });

    await waitFor(() => result.current.data \!== null);
    expect(result.current.error).toBeNull();
    expect(result.current.data).toBeDefined();
    console.log("[TEST] PASS: Retry succeeded and cleared error");
  });

  it("should reset usingMockData flag on successful refetch", async () => {
    process.env.NODE_ENV = "development";
    let callCount = 0;

    server.use(
      rest.get("/api/snapshot", (req, res, ctx) => {
        callCount++;
        if (callCount === 1) return res(ctx.status(500));
        return res(ctx.json({ agents: [] }));
      })
    );

    const { result, waitFor } = renderHook(() => useSnapshot());
    await waitFor(() => result.current.usingMockData === true);

    act(() => result.current.refetch());
    await waitFor(() => result.current.usingMockData === false);

    expect(result.current.usingMockData).toBe(false);
    console.log("[TEST] PASS: usingMockData cleared after successful refetch");
  });
});
```

